  productions?: Prisma.productionsOmit
  products?: Prisma.productsOmit
  products_category?: Prisma.products_categoryOmit
  purchases?: Prisma.purchasesOmit
  purchasing_details?: Prisma.purchasing_detailsOmit
  returns?: Prisma.returnsOmit
  returns_details?: Prisma.returns_detailsOmit
  roles?: Prisma.rolesOmit
  sales?: Prisma.salesOmit
  sales_details?: Prisma.sales_detailsOmit
  suppliers?: Prisma.suppliersOmit
  supplies?: Prisma.suppliesOmit
  users?: Prisma.usersOmit
  workshops?: Prisma.workshopsOmit
  addresses?: Prisma.addressesOmit
